from flask import Flask, request, jsonify
from functools import wraps
from dataclasses import dataclass, asdict
from typing import Dict, Optional
import re

app = Flask(__name__)

VALID_ROLES = {"user", "moderator", "admin"}
VALID_ACCOUNT_STATUSES = {"active", "suspended"}
VALID_SUBSCRIPTION_TIERS = {"free", "pro", "enterprise"}

@dataclass
class User:
    id: int
    email: str
    username: str
    role: str
    account_status: str
    subscription_tier: str

users_db: Dict[int, User] = {
    1: User(1, "admin@example.com", "admin", "admin", "active", "enterprise"),
    2: User(2, "mod@example.com", "moderator1", "moderator", "active", "pro"),
    3: User(3, "user@example.com", "user1", "user", "active", "free"),
}

current_user = users_db[1]

def is_valid_email(email: str) -> bool:
    return bool(re.match(r"^[^@\s]+@[^@\s]+\.[^@\s]+$", email or ""))

def get_user_by_email(email: str) -> Optional[User]:
    email_lower = email.lower()
    for user in users_db.values():
        if user.email.lower() == email_lower:
            return user
    return None

def get_user_by_username(username: str) -> Optional[User]:
    username_lower = username.lower()
    for user in users_db.values():
        if user.username.lower() == username_lower:
            return user
    return None

def admin_required(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        if not current_user or current_user.role != "admin":
            return jsonify({"error": "Forbidden", "message": "Admin access required"}), 403
        return f(*args, **kwargs)
    return wrapper

@app.put("/api/users/<int:user_id>")
@admin_required
def update_user(user_id: int):
    user = users_db.get(user_id)
    if not user:
        return jsonify({"error": "Not Found", "message": "User not found"}), 404

    if not request.is_json:
        return jsonify({"error": "Bad Request", "message": "Request body must be JSON"}), 400

    data = request.get_json(silent=True)
    if data is None:
        return jsonify({"error": "Bad Request", "message": "Invalid JSON body"}), 400

    allowed_fields = {"email", "username", "role", "account_status", "subscription_tier"}
    unknown_fields = set(data.keys()) - allowed_fields
    if unknown_fields:
        return jsonify({
            "error": "Bad Request",
            "message": "Unknown fields provided",
            "fields": sorted(list(unknown_fields))
        }), 400

    if not data:
        return jsonify({"error": "Bad Request", "message": "No fields provided for update"}), 400

    updates = {}

    if "email" in data:
        email = str(data["email"]).strip()
        if not email:
            return jsonify({"error": "Validation Error", "message": "email cannot be empty"}), 422
        if not is_valid_email(email):
            return jsonify({"error": "Validation Error", "message": "Invalid email format"}), 422
        existing = get_user_by_email(email)
        if existing and existing.id != user.id:
            return jsonify({"error": "Conflict", "message": "email is already in use"}), 409
        updates["email"] = email

    if "username" in data:
        username = str(data["username"]).strip()
        if not username:
            return jsonify({"error": "Validation Error", "message": "username cannot be empty"}), 422
        if len(username) < 3 or len(username) > 50:
            return jsonify({"error": "Validation Error", "message": "username must be between 3 and 50 characters"}), 422
        existing = get_user_by_username(username)
        if existing and existing.id != user.id:
            return jsonify({"error": "Conflict", "message": "username is already in use"}), 409
        updates["username"] = username

    if "role" in data:
        role = str(data["role"]).strip().lower()
        if role not in VALID_ROLES:
            return jsonify({
                "error": "Validation Error",
                "message": f"role must be one of: {', '.join(sorted(VALID_ROLES))}"
            }), 422
        updates["role"] = role

    if "account_status" in data:
        account_status = str(data["account_status"]).strip().lower()
        if account_status not in VALID_ACCOUNT_STATUSES:
            return jsonify({
                "error": "Validation Error",
                "message": f"account_status must be one of: {', '.join(sorted(VALID_ACCOUNT_STATUSES))}"
            }), 422
        updates["account_status"] = account_status

    if "subscription_tier" in data:
        subscription_tier = str(data["subscription_tier"]).strip().lower()
        if subscription_tier not in VALID_SUBSCRIPTION_TIERS:
            return jsonify({
                "error": "Validation Error",
                "message": f"subscription_tier must be one of: {', '.join(sorted(VALID_SUBSCRIPTION_TIERS))}"
            }), 422
        updates["subscription_tier"] = subscription_tier

    for field, value in updates.items():
        setattr(user, field, value)

    return jsonify({
        "message": "User updated successfully",
        "user": asdict(user)
    }), 200

